module.exports = (sequelize, DataTypes) => {
    return sequelize.define('blog', {
        title: {
            type: DataTypes.STRING,
            allowNull: false,
            field: 'title'
        },
        text: {
            type: DataTypes.TEXT,
            allowNull: false,
            field: 'text'
        },
        createdBy: {
            type: DataTypes.INTEGER,
            allowNull: false,
            field: 'created_by'
        },
        organizationId: {
            type: DataTypes.INTEGER,
            allowNull: false,
            field: 'organization_id'
        }
    }, {
        timestamps: true,
        createdAt: 'created_at',
        updatedAt: 'updated_at'
    });
};